import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;

public class DebugTest {
    public static void main(String[] args) {
        String html = "<body><p><textarea>one<p>two";
        Document doc = Jsoup.parse(html);
        System.out.println("HTML Output: " + doc.body().html());

        // Let's see what elements we have
        System.out.println("Textarea text: " + doc.select("textarea").first().text());
        System.out.println("Second p text: " + doc.select("p").get(1).text());
        System.out.println("Number of p elements: " + doc.select("p").size());
    }
}

